//! Reference validation tests: compare hyburn outputs against TVB hybrid simulator.
//!
//! These tests load .npy reference datasets generated by the Python scripts
//! in ref/ (using tvb-root hybrid-model branch) and verify that hyburn's
//! numerical outputs match within the expected tolerance.
//!
//! Tolerance rationale:
//!   - hyburn uses f32, TVB uses f64 internally → ~1e-7 precision floor
//!   - Different operation ordering in GPU/NDArray vs CPU → accumulate errors
//!   - Single sim: rel err < 1e-3 (short runs, minimal drift)
//!   - Sweep: rel err < 5e-3 (longer runs, more drift)
//!   - BOLD: rel err < 1e-2 (stacked integration + balloon model)
//!   - Features: rel err < 1e-2 (statistics over long series)

use burn::backend::ndarray::NdArray;
use hyburn::config::{InitialStateConfig, MonitorConfig, NetworkConfig, SimConfig, SubnetworkConfig};
use hyburn::engine::bold_monitor::BoldMonitor;
use hyburn::engine::integrator::IntegratorKind;
use hyburn::engine::HybridEngine;
use hyburn::io::read_npy_f32;

type B = NdArray<f32>;

/// Helper: load a reference .npy file from the ref/ directory.
fn load_ref_npy(name: &str) -> (Vec<f32>, Vec<usize>) {
    let path = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("ref")
        .join(name);
    read_npy_f32(&path).unwrap_or_else(|e| panic!("Failed to load ref/{}: {}", name, e))
}

/// Helper: compare two f32 slices with relative + absolute tolerance.
///
/// For values where |expected| < atol_floor, uses absolute tolerance instead of
/// relative (avoids division-by-near-zero).
fn assert_allclose_rel(actual: &[f32], expected: &[f32], rtol: f32, label: &str) {
    assert_eq!(actual.len(), expected.len(),
        "{}: length mismatch: actual={}, expected={}", label, actual.len(), expected.len());

    let atol_floor = 1e-4; // below this expected magnitude, use absolute comparison

    for (i, (&a, &e)) in actual.iter().zip(expected.iter()).enumerate() {
        if !a.is_finite() || !e.is_finite() {
            panic!("{}: non-finite at index {}: actual={}, expected={}", label, i, a, e);
        }
        let abs_diff = (a - e).abs();
        if e.abs() < atol_floor {
            // Near-zero expected: use absolute tolerance
            assert!(
                abs_diff < atol_floor,
                "{}: mismatch at index {}: actual={}, expected={}, abs_diff={} > atol={}",
                label, i, a, e, abs_diff, atol_floor
            );
        } else {
            let rel_err = abs_diff / e.abs();
            assert!(
                rel_err <= rtol,
                "{}: mismatch at index {}: actual={}, expected={}, rel_err={:.6} > rtol={}",
                label, i, a, e, rel_err, rtol
            );
        }
    }
}

/// Helper: reshape flat trajectory from hyburn's format.
/// Hyburn stores trajectory as: for each step, [nvar*nnodes*nmodes] values
/// concatenated. So total length = n_steps * nvar * nnodes * nmodes.
/// Returns reshaped as [n_steps, nvar, nnodes] (assuming nmodes=1, flattened).
fn reshape_trajectory(flat: &[f32], n_steps: usize, nvar: usize, nnodes: usize) -> Vec<f32> {
    let step_len = nvar * nnodes; // nmodes=1
    assert_eq!(flat.len(), n_steps * step_len,
        "Trajectory length {} != {} * {}", flat.len(), n_steps, step_len);
    // Already in the right order: [step0_V0, step0_V1, step0_W0, step0_W1, step1_...]
    // Which matches TVB's [n_steps, nvar, nnodes] flattened in C order.
    flat.to_vec()
}

// ---------------------------------------------------------------------------
// Single simulation reference tests
