#[test]
fn test_ref_g2do_small_final_state() {
    let (expected_flat, expected_shape) = load_ref_npy("single_sim/g2do_small_final_state.npy");
    // TVB shape: [nvar=2, nnodes=2, nmodes=1] → flat [V0, V1, W0, W1]

    // Build hyburn config matching ref/configs.py g2do_small
    let cfg = SimConfig {
        sim_length: 10.0,
        dt: 0.1,
        integrator: IntegratorKind::Heun,
        nsig: 0.0,
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Generic2dOscillator".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0, 0.5, 0.5]),
                params: hyburn::model::g2do::g2do_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");

    engine.run(100); // 10.0 / 0.1 = 100 steps

    let (actual_flat, actual_shape) = hyburn::io::tensor_to_flat_f32(engine.states[0].clone());

    assert_eq!(actual_shape, expected_shape,
        "Shape mismatch: actual={:?} expected={:?}", actual_shape, expected_shape);
    assert_allclose_rel(&actual_flat, &expected_flat, 1e-3, "g2do_small_final_state");
}

#[test]
fn test_ref_g2do_small_trajectory() {
    let (expected_flat, _expected_shape) = load_ref_npy("single_sim/g2do_small_trajectory.npy");
    // TVB shape: [101, 2, 2, 1] → flat [step0_V0, step0_V1, step0_W0, step0_W1, ...]

    let cfg = SimConfig {
        sim_length: 10.0,
        dt: 0.1,
        integrator: IntegratorKind::Heun,
        nsig: 0.0,
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Generic2dOscillator".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0, 0.5, 0.5]),
                params: hyburn::model::g2do::g2do_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");

    let n_steps = 100;
    engine.run(n_steps);

    // hyburn trajectory includes step 0 through step n_steps (n_steps+1 snapshots)
    // But hyburn's trajectory field records state AFTER each step, not including initial state.
    // Let's check by looking at the length.
    let traj = &engine.trajectory;
    let nvar = 2;
    let nnodes = 2;
    let step_len = nvar * nnodes; // nmodes=1

    // hyburn records one snapshot per step (after integration).
    // The initial state is NOT in the trajectory — it starts from step 1.
    // So trajectory has n_steps snapshots, not n_steps+1.
    assert_eq!(traj.len(), n_steps * step_len,
        "Trajectory length: {} != {} * {}", traj.len(), n_steps, step_len);

    // Compare against TVB reference (which has n_steps+1 entries including step 0).
    // TVB flat layout: [step0 (4 vals), step1 (4 vals), ..., step100 (4 vals)]
    // TVB step0 = initial state, step1 = after 1 step, etc.
    // hyburn traj[0..4] = after step 1 = TVB step1

    // Extract TVB steps 1..=100 (skip step 0 which is initial state)
    let tvb_traj = reshape_trajectory(&expected_flat, 101, nvar, nnodes);
    let tvb_steps_1_to_n: Vec<f32> = (1..=n_steps)
        .flat_map(|s| tvb_traj[s * step_len..(s + 1) * step_len].to_vec())
        .collect();

    assert_allclose_rel(traj, &tvb_steps_1_to_n, 1e-3, "g2do_small_trajectory");
}

