#[test]
fn test_ref_g2do_sweep_final_states() {
    let (expected_flat, expected_shape) = load_ref_npy("sweep/g2do_I_ext_sweep_final_states.npy");
    // TVB shape: [128, 2, 74, 1]

    assert_eq!(expected_shape[0], 128, "Expected 128 sweep points");
    let nvar = expected_shape[1];
    let nnodes = expected_shape[2];

    let sweep_values: &[f32] = &[
        -0.50, -0.48, -0.47, -0.45, -0.43, -0.42, -0.40, -0.38,
        -0.37, -0.35, -0.33, -0.32, -0.30, -0.28, -0.27, -0.25,
        -0.23, -0.22, -0.20, -0.18, -0.17, -0.15, -0.13, -0.12,
        -0.10, -0.08, -0.07, -0.05, -0.03, -0.02, 0.00, 0.02,
        0.03, 0.05, 0.07, 0.08, 0.10, 0.12, 0.13, 0.15,
        0.17, 0.18, 0.20, 0.22, 0.23, 0.25, 0.27, 0.28,
        0.30, 0.32, 0.33, 0.35, 0.37, 0.38, 0.40, 0.42,
        0.43, 0.45, 0.47, 0.48, 0.50, 0.52, 0.53, 0.55,
        0.57, 0.58, 0.60, 0.62, 0.63, 0.65, 0.67, 0.68,
        0.70, 0.72, 0.73, 0.75, 0.77, 0.78, 0.80, 0.82,
        0.83, 0.85, 0.87, 0.88, 0.90, 0.92, 0.93, 0.95,
        0.97, 0.98, 1.00, 1.02, 1.03, 1.05, 1.07, 1.08,
        1.10, 1.12, 1.13, 1.15, 1.17, 1.18, 1.20, 1.22,
        1.23, 1.25, 1.27, 1.28, 1.30, 1.32, 1.33, 1.35,
        1.37, 1.38, 1.40, 1.42, 1.43, 1.45, 1.47, 1.48,
        1.50, 1.50, 1.50, 1.50, 1.50, 1.50, 1.50, 1.50,
    ];

    let point_len = nvar * nnodes; // nmodes=1, flattened per sweep point
    let device: <B as burn::prelude::Backend>::Device = Default::default();

    // Test a representative subset (not all 128 — too slow)
    let test_indices: Vec<usize> = vec![0, 31, 63, 95, 127]; // ~every quarter

    for &si in &test_indices {
        let i_ext = sweep_values[si];
        let mut params = hyburn::model::g2do::g2do_default_params();
        params[1] = i_ext; // I is the second parameter

        let cfg = SimConfig {
            sim_length: 1000.0,
            dt: 0.1,
            integrator: IntegratorKind::Heun,
            nsig: 0.0,
            network: NetworkConfig {
                subnetworks: vec![SubnetworkConfig {
                    model: "Generic2dOscillator".to_string(),
                    nnodes: 74,
                    nmodes: 1,
                    initial_state: InitialStateConfig::NpyPath(
                        "examples/init_g2do_74.npy".to_string(),
                    ),
                    params,
                }],
                projections: vec![],
            },
            monitors: vec![],
            stimuli: vec![],
        };

        let mut engine = HybridEngine::<B>::from_config(cfg, device)
            .unwrap_or_else(|e| panic!("Sweep point {} (I={}): engine failed: {}", si, i_ext, e));
        engine.run(10000);

        let (actual_flat, actual_shape) = hyburn::io::tensor_to_flat_f32(engine.states[0].clone());

        // Extract expected for this sweep point
        let expected_start = si * point_len;
        let expected_end = expected_start + point_len;
        let expected_point = &expected_flat[expected_start..expected_end];

        assert_eq!(actual_shape, &expected_shape[1..],
            "Sweep point {} shape mismatch: actual={:?} expected={:?}",
            si, actual_shape, &expected_shape[1..]);

        let label = format!("sweep_point_{}_I_{:.2}", si, i_ext);
        assert_allclose_rel(&actual_flat, expected_point, 5e-3, &label);
    }
}

// ---------------------------------------------------------------------------
// BOLD monitor reference tests
// ---------------------------------------------------------------------------

/// Test that hyburn's Balloon-Windkessel model matches the Python reference
/// when fed identical neural input.
///
/// This is a pure BW model comparison: we load neural_var0 from the reference
/// .npy, feed it through hyburn's BoldMonitor, and compare the output against
/// the Python-generated BOLD signal.
#[test]
fn test_ref_bold_model_against_python() {
    // Load neural input: [n_steps+1, nnodes] of var0
    let (neural_flat, neural_shape) =
        load_ref_npy("bold/g2do_small_bold_neural.npy");
    // Shape: [20001, 2]
    let n_total = neural_shape[0]; // includes step 0
    let nnodes = neural_shape[1];
    assert_eq!(nnodes, 2, "Expected 2 nodes");
    let n_steps = n_total - 1; // 20000 integration steps

    // Load expected BOLD: [n_bold_samples, nnodes]
    let (expected_bold, expected_bold_shape) =
        load_ref_npy("bold/g2do_small_bold.npy");
    let n_bold_samples = expected_bold_shape[0];
    assert_eq!(expected_bold_shape[1], nnodes, "BOLD nnodes mismatch");

    // Build hyburn BoldMonitor matching Python parameters
    let bold_period: usize = 10;
    let dt_neural: f64 = 0.1; // ms
    let tr: f64 = 2.0;        // seconds
    let mut monitor = BoldMonitor::new(
        0,             // target_subnetwork
        nnodes,
        bold_period,
        tr,
        dt_neural,
        None,          // default BoldParameters
    );

    // Feed neural input: skip step 0 (initial state), use steps 1..=n_steps
    // hyburn's engine accumulates var0 after each step, so we feed
    // neural[step] for step = 1..=n_steps
    for step in 1..=n_steps {
        let offset = step * nnodes;
        let neural_input = &neural_flat[offset..offset + nnodes];
        monitor.accumulate(neural_input);
    }

    // Flush any remaining accumulator
    let _ = monitor.flush();

    // Get the BOLD signal data
    let actual_bold = &monitor.data;
    let actual_n_samples = monitor.n_samples();

    // The Python reference records a BOLD sample every bold_period steps.
    // Expected: n_bold_samples = n_steps / bold_period = 2000
    assert_eq!(actual_n_samples, n_bold_samples,
        "BOLD sample count: actual={}, expected={}", actual_n_samples, n_bold_samples);

    // Compare BOLD signals — BOLD is a stacked integration so more drift is expected
    assert_allclose_rel(actual_bold, &expected_bold, 5e-2, "bold_signal");
}

/// Test BOLD monitor end-to-end: run a short G2DO simulation with BOLD
/// and verify the monitor accumulates and produces finite output.
#[test]
fn test_ref_bold_e2e() {
    let cfg = SimConfig {
        sim_length: 2000.0,  // 2 s
        dt: 0.1,
        integrator: IntegratorKind::Heun,
        nsig: 0.0,
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Generic2dOscillator".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0, 0.5, 0.5]),
                params: hyburn::model::g2do::g2do_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![MonitorConfig {
            monitor_type: "Bold".to_string(),
            period: None,
            tr: Some(2.0),
            bold_period: Some(10),
        }],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");
    engine.run(20000); // 2000.0 / 0.1
    engine.flush_bold_monitors();

    // Verify BOLD monitor has data
    assert!(!engine.bold_monitors.is_empty(), "No BOLD monitors attached");
    let monitor = &engine.bold_monitors[0];
    assert!(monitor.n_samples() > 0, "BOLD monitor has no samples");
    assert!(monitor.data.iter().all(|v| v.is_finite()),
        "BOLD data contains non-finite values");
}

// ---------------------------------------------------------------------------
// Feature extraction reference tests
// ---------------------------------------------------------------------------

/// Test that hyburn's classic feature extraction (mean, var, autocorr-lag1)
/// matches the Python reference.
#[test]
fn test_ref_features_classic() {
    // Run a short G2DO simulation and extract classic features
    let cfg = SimConfig {
        sim_length: 10.0,
        dt: 0.1,
        integrator: IntegratorKind::Heun,
        nsig: 0.0,
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Generic2dOscillator".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0, 0.5, 0.5]),
                params: hyburn::model::g2do::g2do_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");
    engine.run(100);

    // Get trajectory (flat: 100 steps x 2 nvar x 2 nnodes = 400 values)
    let traj = &engine.trajectory;
    let nvar = 2;
    let nnodes = 2;
    let step_len = nvar * nnodes;
    assert_eq!(traj.len(), 100 * step_len);

    // Extract var0 series (averaged over nodes) matching Python reference
    // traj layout per step: [V0, V1, W0, W1]
    // var0 = first nnodes entries = [V0, V1]
    let var0_mean: Vec<f32> = (0..100)
        .map(|s| {
            let v0 = traj[s * step_len];
            let v1 = traj[s * step_len + 1];
            (v0 + v1) / 2.0
        })
        .collect();

    // Compute classic features: mean, var, lag-1 autocorrelation
    let n = var0_mean.len() as f32;
    let mean = var0_mean.iter().copied().sum::<f32>() / n;
    let var = var0_mean.iter().map(|v| (v - mean).powi(2)).sum::<f32>() / n;
    let ac1 = if var > 1e-12 {
        let cov: f32 = (0..var0_mean.len() - 1)
            .map(|i| (var0_mean[i] - mean) * (var0_mean[i + 1] - mean))
            .sum::<f32>()
            / (n - 1.0);
        cov / var
    } else {
        0.0
    };

    let actual = vec![mean, var, ac1];

    // Load Python reference
    let (expected, _shape) =
        load_ref_npy("features/g2do_small_v0_classic_features.npy");

    // Note: Python ref was computed from TVB trajectory (101 steps including step 0),
    // hyburn trajectory has 100 steps (after each integration, no initial state).
    // The feature values will differ slightly due to different trajectory lengths.
    // Use a generous tolerance for feature comparison.
    assert_allclose_rel(&actual, &expected, 1e-1, "classic_features_v0");
}

/// Test that hyburn's spectral feature extraction produces reasonable output.
///
/// Python reference comparison is not feasible for short high-fs series
/// (all EEG band powers are zero with fs=10000 Hz and only 100 samples).
/// Instead, we verify hyburn's spectral features are well-formed.
#[test]
fn test_ref_features_spectral() {
    // Run a short G2DO simulation with more steps for meaningful spectral content
    let cfg = SimConfig {
        sim_length: 1000.0,  // 1 s → 10000 samples at dt=0.1ms
        dt: 0.1,
        integrator: IntegratorKind::Heun,
        nsig: 0.0,
        network: NetworkConfig {
            subnetworks: vec![SubnetworkConfig {
                model: "Generic2dOscillator".to_string(),
                nnodes: 2,
                nmodes: 1,
                initial_state: InitialStateConfig::Inline(vec![0.0, 0.0, 0.5, 0.5]),
                params: hyburn::model::g2do::g2do_default_params(),
            }],
            projections: vec![],
        },
        monitors: vec![],
        stimuli: vec![],
    };

    let device = Default::default();
    let mut engine = HybridEngine::<B>::from_config(cfg, device)
        .expect("Engine creation failed");
    engine.run(10000);

    let traj = &engine.trajectory;
    let nvar = 2;
    let nnodes = 2;
    let step_len = nvar * nnodes;

    // Extract var0 series (averaged over nodes)
    let var0_mean: Vec<f32> = (0..10000)
        .map(|s| {
            let v0 = traj[s * step_len];
            let v1 = traj[s * step_len + 1];
            (v0 + v1) / 2.0
        })
        .collect();

    // Use hyburn's spectral feature extractor
    let fs = 10000.0_f64; // Hz
    let feat_data = hyburn::sbi::features::spectral::spectral_features(
        &var0_mean, fs,
    );

    // Verify: 5 band powers + 4 moments = 9 features
    assert_eq!(feat_data.len(), 9, "Spectral features should have 9 elements");

    // All features should be finite
    for (i, &v) in feat_data.iter().enumerate() {
        assert!(v.is_finite(), "spectral feature {} is non-finite: {}", i, v);
    }

    // Band powers should sum to approximately 1.0 (they're normalized by total power)
    let band_sum: f32 = feat_data[0..5].iter().sum();
    assert!(
        (band_sum - 1.0).abs() < 0.3,
        "Band power sum should be near 1.0 (got {})",
        band_sum
    );

    // Centroid should be positive and finite
    assert!(feat_data[5] > 0.0, "Spectral centroid should be positive: {}", feat_data[5]);
    // Spread should be positive
    assert!(feat_data[6] > 0.0, "Spectral spread should be positive: {}", feat_data[6]);
}
